function parseQueryString(value) {
  if (value === undefined || value === null || value === '') return {}
  if (typeof value === 'object' && !Array.isArray(value)) return value
  const text = String(value).trim()
  if (!text) return {}
  if (text.startsWith('{')) {
    try {
      const parsed = JSON.parse(text)
      return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : {}
    } catch {}
  }
  const source = text.startsWith('?') ? text.slice(1) : text
  const result = {}
  for (const pair of source.split('&')) {
    if (!pair) continue
    const separatorIndex = pair.indexOf('=')
    const rawKey = separatorIndex >= 0 ? pair.slice(0, separatorIndex) : pair
    const rawValue = separatorIndex >= 0 ? pair.slice(separatorIndex + 1) : ''
    const key = decodeURIComponent(rawKey.replace(/\+/g, ' ')).trim()
    const paramValue = decodeURIComponent(rawValue.replace(/\+/g, ' ')).trim()
    if (!key || paramValue === '') continue
    if (result[key] === undefined) result[key] = paramValue
    else if (Array.isArray(result[key])) result[key].push(paramValue)
    else result[key] = [result[key], paramValue]
  }
  return result
}

function parseObject(value) {
  if (typeof value === 'string') {
    try {
      const parsed = JSON.parse(value)
      return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : parseQueryString(value)
    } catch {
      return parseQueryString(value)
    }
  }
  return value && typeof value === 'object' && !Array.isArray(value) ? value : {}
}

function readInput() {
  const raw = parseObject($json)
  const input = { ...raw }
  for (const key of ['json', 'body', 'data', 'input', 'workflowInputs', 'parameters', 'args']) {
    Object.assign(input, parseObject(raw[key]))
  }
  Object.assign(input, parseQueryString(raw.query))
  Object.assign(input, parseQueryString(raw.queryString))
  return input
}

function present(value) {
  if (Array.isArray(value)) return value.length > 0 ? value : undefined
  return value !== undefined && value !== null && value !== '' ? value : undefined
}

function toPositiveInteger(value, fallback) {
  const normalized = present(value)
  if (normalized === undefined || Array.isArray(normalized)) return fallback
  const parsed = Number(normalized)
  return Number.isInteger(parsed) && parsed > 0 ? parsed : fallback
}

const input = readInput()
const query = String(present(input.query) ?? '').trim()
const limit = Math.min(toPositiveInteger(input.limit, 3), 5)
return [{ json: { query, limit } }]

const prepared = $('Prepare Input').item.json
const handbookText = String($json.content ?? '').trim()
if (!handbookText) {
  return [{ json: { documents: [], warnings: ['Khong doc duoc noi dung tu Google Docs.'], sources: [{ type: 'drive', name: 'Google Docs: HOTEL_INTERNAL_OPERATIONS_GUIDE' }] } }]
}

function normalize(value) {
  return String(value ?? '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/đ/g, 'd')
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
}

function tokenize(value) {
  return normalize(value)
    .split(' ')
    .filter((token) => token.length >= 2)
}

function isHeading(line) {
  const trimmed = line.trim()
  return /^(?:#{1,6}\s*)?(?:\d+(?:\.\d+)*\.\s+.+|Thông tin tài liệu|Phạm vi sử dụng)$/u.test(trimmed)
}

function titleFromHeading(line) {
  return line.trim().replace(/^#{1,6}\s*/, '')
}

function splitSections(text) {
  const lines = text.split(/\r?\n/)
  const sections = []
  let currentTitle = 'Tài liệu tổng quan'
  let currentLines = []

  function flush() {
    const content = currentLines.join('\n').trim()
    if (content) sections.push({ title: currentTitle, content })
  }

  for (const line of lines) {
    if (isHeading(line)) {
      flush()
      currentTitle = titleFromHeading(line)
      currentLines = [line]
    } else {
      currentLines.push(line)
    }
  }

  flush()
  return sections
}

function scoreSection(section, queryTokens) {
  const normalizedTitle = normalize(section.title)
  const normalizedContent = normalize(section.content)
  let score = 0
  for (const token of queryTokens) {
    if (normalizedTitle.includes(token)) score += 4
    const matches = normalizedContent.match(new RegExp('(^|\\s)' + token + '(?=\\s|$)', 'g'))
    if (matches) score += matches.length
  }
  return score
}

function makeSnippet(content, queryTokens) {
  const plain = content
    .replace(/^#{1,6}\s+/gm, '')
    .replace(/\|/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
  const normalizedPlain = normalize(plain)
  let start = 0
  for (const token of queryTokens) {
    const index = normalizedPlain.indexOf(token)
    if (index >= 0) {
      start = Math.max(0, index - 90)
      break
    }
  }
  return plain.slice(start, start + 320)
}

const query = String(prepared.query ?? '').trim()
const limit = Number(prepared.limit ?? 3)
const sections = splitSections(handbookText)
const queryTokens = tokenize(query)

const ranked = sections
  .map((section) => ({ ...section, score: scoreSection(section, queryTokens) }))
  .filter((section) => queryTokens.length === 0 || section.score > 0)
  .sort((a, b) => b.score - a.score || a.title.localeCompare(b.title, 'vi'))
  .slice(0, limit)

const documents = ranked.map((section) => ({
  title: section.title,
  snippet: makeSnippet(section.content, queryTokens),
  content: section.content.slice(0, 1800),
  score: section.score,
  source: 'Google Docs: HOTEL_INTERNAL_OPERATIONS_GUIDE'
}))

return [{
  json: {
    documents,
    warnings: documents.length === 0 ? ['Khong tim thay muc tai lieu phu hop voi truy van.'] : [],
    sources: [{ type: 'drive', name: 'Google Docs: HOTEL_INTERNAL_OPERATIONS_GUIDE' }]
  }
}]
